/**
 * DoorDesignerData.js
 * 
 * Loads door designer configuration from Supabase (scraped data).
 * Provides instant access to all options without API calls.
 */

import { supabase } from '../config/supabaseClient';
import AsyncStorage from '@react-native-async-storage/async-storage';
// Bundled snapshot — generated by `npm run snapshot` before each release.
import bundledDesigner from '../assets/designer-snapshot.json';

const CACHE_KEY = '@bsw_door_designer_v1';
const CACHE_TIMESTAMP_KEY = '@bsw_door_designer_ts_v1';
const CACHE_TTL = 24 * 60 * 60 * 1000; // 24h

let cachedCategories = null;
let cachedOptions = null;

/**
 * Load all categories (heading types)
 */
export async function loadCategories() {
  if (cachedCategories) return cachedCategories;

  const { data, error } = await supabase
    .from('door_designer_categories')
    .select('*')
    .order('sort_order');

  if (error) {
    console.error('[DoorDesignerData] Error loading categories:', error.message);
    return [];
  }

  cachedCategories = data;
  return data;
}

/**
 * Load all options, optionally filtered by heading_type_id
 */
export async function loadOptions(headingTypeId = null, parentOptionId = null) {
  const query = supabase
    .from('door_designer_options')
    .select('*')
    .eq('is_active', true)
    .order('sort_order');

  if (headingTypeId) {
    query.eq('heading_type_id', headingTypeId);
  }

  if (parentOptionId !== undefined && parentOptionId !== null) {
    query.eq('parent_option_id', parentOptionId);
  }

  const { data, error } = await query;

  if (error) {
    console.error('[DoorDesignerData] Error loading options:', error.message);
    return [];
  }

  return data;
}

/**
 * Load the full configurator data set in one go.
 * Returns { categories, optionsByCategory }
 */
export async function loadAllDesignerData() {
  // 1. In-memory cache (instant)
  if (cachedCategories && cachedOptions) {
    return { categories: cachedCategories, options: cachedOptions };
  }

  // 2. Try AsyncStorage disk cache
  try {
    const [cachedJson, cachedTs] = await Promise.all([
      AsyncStorage.getItem(CACHE_KEY),
      AsyncStorage.getItem(CACHE_TIMESTAMP_KEY),
    ]);

    if (cachedJson) {
      const parsed = JSON.parse(cachedJson);
      cachedCategories = parsed.categories;
      cachedOptions = parsed.options;
      console.log('[DoorDesignerData] Loaded from disk cache');

      const age = Date.now() - parseInt(cachedTs || '0', 10);
      if (age > CACHE_TTL) {
        console.log('[DoorDesignerData] Cache stale, refreshing in background...');
        fetchAndCacheFromSupabase().catch(err =>
          console.error('[DoorDesignerData] Background refresh failed:', err.message)
        );
      }

      return { categories: cachedCategories, options: cachedOptions };
    }
  } catch (e) {
    console.log('[DoorDesignerData] AsyncStorage read error:', e.message);
  }

  // 3. First launch — seed from the bundled snapshot and refresh in the
  //    background so the door designer renders instantly.
  if (bundledDesigner && bundledDesigner.categories && bundledDesigner.options) {
    cachedCategories = bundledDesigner.categories;
    cachedOptions = bundledDesigner.options;
    const optCount = Object.values(bundledDesigner.options).reduce((n, a) => n + a.length, 0);
    console.log(`[DoorDesignerData] Seeded from bundled snapshot (${bundledDesigner.categories.length} categories, ${optCount} options)`);
    fetchAndCacheFromSupabase().catch(err =>
      console.error('[DoorDesignerData] Initial refresh failed:', err.message)
    );
    return { categories: cachedCategories, options: cachedOptions };
  }

  // 4. No bundled snapshot — fall back to a blocking network fetch.
  return fetchAndCacheFromSupabase();
}

async function fetchAndCacheFromSupabase() {
  console.log('[DoorDesignerData] Loading all data from Supabase...');

  const [categories, allOptions] = await Promise.all([
    loadCategories(),
    loadOptions(),
  ]);

  const optionsByCategory = {};
  allOptions.forEach(opt => {
    const key = opt.heading_type_id;
    if (!optionsByCategory[key]) optionsByCategory[key] = [];
    optionsByCategory[key].push(opt);
  });

  cachedCategories = categories;
  cachedOptions = optionsByCategory;

  try {
    await Promise.all([
      AsyncStorage.setItem(
        CACHE_KEY,
        JSON.stringify({ categories, options: optionsByCategory }),
      ),
      AsyncStorage.setItem(CACHE_TIMESTAMP_KEY, Date.now().toString()),
    ]);
    console.log(`[DoorDesignerData] Cached ${categories.length} categories, ${allOptions.length} options to disk`);
  } catch (e) {
    console.log('[DoorDesignerData] AsyncStorage write error:', e.message);
  }

  return { categories, options: optionsByCategory };
}

/**
 * Get door styles for a specific range
 */
export async function getStylesForRange(rangeOriginalId) {
  const { data, error } = await supabase
    .from('door_designer_options')
    .select('*')
    .eq('heading_type_id', 11)
    .eq('parent_option_id', rangeOriginalId)
    .eq('is_active', true)
    .order('sort_order');

  if (error) {
    console.error('[DoorDesignerData] Error loading styles for range:', error.message);
    return [];
  }

  return data;
}

/**
 * Get options for a category, excluding hidden ones
 */
export function getVisibleOptions(optionsByCategory, categoryId, parentId = null) {
  const all = optionsByCategory[categoryId] || [];
  
  let filtered = all.filter(o => !o.valid_but_hidden);
  
  // If parentId specified (for door styles), filter by parent
  if (parentId) {
    filtered = filtered.filter(o => o.parent_option_id === parentId);
  }
  
  return filtered;
}

/**
 * Clear cache (e.g., if you re-scrape)
 */
export function clearCache() {
  cachedCategories = null;
  cachedOptions = null;
  AsyncStorage.multiRemove([CACHE_KEY, CACHE_TIMESTAMP_KEY]).catch(() => {});
}

